var documenterSearchIndex = {"docs":
[{"category":"section","location":"guide/configuration/#configuration","page":"Configuration","text":"LLMWiki is configured through the WikiConfig struct, which can be set programmatically or persisted as a YAML file.","title":"Configuration"},{"category":"section","location":"guide/configuration/#WikiConfig-Fields","page":"Configuration","text":"Field Type Default Description\nroot String \".\" Root directory for the wiki\nsources_dir String \"sources\" Directory for raw input documents\nwiki_dir String \"wiki\" Output directory for generated pages\nconcepts_dir String \"wiki/concepts\" Directory for concept pages\nqueries_dir String \"wiki/queries\" Directory for saved query pages\nindex_file String \"wiki/index.md\" Path to the auto-generated index\nlog_file String \"wiki/log.md\" Path to the operation log\nstate_dir String \".llmwiki\" Directory for state and config files\nstate_file String \".llmwiki/state.json\" Path to the compilation state file\nmodel String \"qwen3:8b\" LLM model name\nprovider Symbol :ollama LLM provider (:ollama, :openai, :azure)\nembedding_model String \"nomic-embed-text\" Model for semantic embeddings\napi_url Union{Nothing,String} nothing Custom API URL (nothing = provider default)\nmax_concepts_per_source Int 8 Maximum concepts extracted per source\ncompile_concurrency Int 3 Concurrency limit for compilation\nmax_related_pages Int 5 Related pages loaded as context for generation\nquery_page_limit Int 8 Max pages selected per query\nsearch_top_k Int 10 Default number of search results\nsimilarity_threshold Float64 0.7 Minimum similarity for semantic search","title":"WikiConfig Fields"},{"category":"section","location":"guide/configuration/#Programmatic-Configuration","page":"Configuration","text":"using LLMWiki\n\nconfig = default_config(\"my-wiki\")\n\n# LLM settings\nconfig.model = \"qwen3:8b\"\nconfig.provider = :ollama\nconfig.api_url = \"http://localhost:11434\"\n\n# Compilation tuning\nconfig.max_concepts_per_source = 10\nconfig.max_related_pages = 8\n\n# Search\nconfig.search_top_k = 20\nconfig.similarity_threshold = 0.8\n\n# Persist to disk\nsave_config(config)","title":"Programmatic Configuration"},{"category":"section","location":"guide/configuration/#YAML-Configuration-File","page":"Configuration","text":"Configuration is stored at .llmwiki/config.yaml. Only non-default values are written:\n\nmodel: \"gpt-4o\"\nprovider: \"openai\"\nmax_concepts_per_source: 10\nsearch_top_k: 20","title":"YAML Configuration File"},{"category":"section","location":"guide/configuration/#Loading-from-YAML","page":"Configuration","text":"# Load existing config (falls back to defaults if file missing)\nconfig = load_config(\"my-wiki\")","title":"Loading from YAML"},{"category":"section","location":"guide/configuration/#Provider-Setup","page":"Configuration","text":"","title":"Provider Setup"},{"category":"section","location":"guide/configuration/#Ollama-(Local)","page":"Configuration","text":"config.provider = :ollama\nconfig.model = \"qwen3:8b\"\nconfig.api_url = \"http://localhost:11434\"  # default, can omit\nconfig.embedding_model = \"nomic-embed-text\"","title":"Ollama (Local)"},{"category":"section","location":"guide/configuration/#OpenAI","page":"Configuration","text":"config.provider = :openai\nconfig.model = \"gpt-4o\"\nconfig.embedding_model = \"text-embedding-3-small\"\n# Set OPENAI_API_KEY environment variable","title":"OpenAI"},{"category":"section","location":"guide/configuration/#Azure-AI","page":"Configuration","text":"config.provider = :azure\nconfig.model = \"gpt-4o\"\nconfig.api_url = \"https://your-resource.openai.azure.com/\"\n# Set AZURE_OPENAI_API_KEY environment variable","title":"Azure AI"},{"category":"section","location":"guide/configuration/#Directory-Layout","page":"Configuration","text":"After init_wiki creates the structure:\n\nmy-wiki/                       # config.root\n├── sources/                   # config.sources_dir — raw input documents\n│   ├── article.md\n│   ├── paper.pdf\n│   └── webpage.md\n├── wiki/                      # config.wiki_dir — generated output\n│   ├── concepts/              # config.concepts_dir — concept pages\n│   │   ├── machine-learning.md\n│   │   ├── neural-networks.md\n│   │   └── backpropagation.md\n│   ├── queries/               # config.queries_dir — saved query answers\n│   │   └── how-does-backprop-work.md\n│   ├── index.md               # config.index_file — table of contents\n│   └── log.md                 # config.log_file — operation log\n└── .llmwiki/                  # config.state_dir — internal state\n    ├── config.yaml            # persisted configuration\n    ├── state.json             # compilation state (source hashes, concepts)\n    └── lock                   # filesystem lock during compilation","title":"Directory Layout"},{"category":"section","location":"guide/configuration/#Path-Resolution","page":"Configuration","text":"All directory and file paths in WikiConfig can be relative or absolute. Use resolve_paths! to make them absolute relative to config.root:\n\nconfig = WikiConfig(root=\"my-wiki\", sources_dir=\"sources\")\nresolve_paths!(config)\n# config.sources_dir is now an absolute path like \".../my-wiki/sources\"\n\ndefault_config and init_wiki call resolve_paths! automatically.","title":"Path Resolution"},{"category":"section","location":"guide/compilation/#compilation","page":"Compilation Pipeline","text":"The compilation pipeline is the core of LLMWiki. It transforms raw source documents into a structured, cross-linked wiki through a deterministic 12-step process.","title":"Compilation Pipeline"},{"category":"section","location":"guide/compilation/#Overview","page":"Compilation Pipeline","text":"Sources (immutable)          Wiki (LLM-generated)         Schema\n┌──────────────┐     ┌──────────────────────────┐    ┌──────────┐\n│ article.md   │     │ wiki/concepts/            │    │ config   │\n│ paper.pdf    │────▶│   rust-lang.md            │    │ state    │\n│ website.html │     │   ownership.md            │    │ log      │\n└──────────────┘     │   type-system.md          │    └──────────┘\n                     │ wiki/index.md             │\n                     └──────────────────────────┘","title":"Overview"},{"category":"section","location":"guide/compilation/#The-12-Steps","page":"Compilation Pipeline","text":"result = compile!(config)\n\nThe compile! function executes these steps in order:","title":"The 12 Steps"},{"category":"section","location":"guide/compilation/#Step-1:-Acquire-Lock","page":"Compilation Pipeline","text":"A filesystem lock (.llmwiki/lock) prevents concurrent compilations. Stale locks older than 10 minutes are automatically broken.","title":"Step 1: Acquire Lock"},{"category":"section","location":"guide/compilation/#Step-2:-Load-State-and-Detect-Changes","page":"Compilation Pipeline","text":"The compiler loads the persisted WikiState from .llmwiki/state.json, then walks the sources/ directory, computing SHA-256 hashes for every file. Each source is classified as:\n\nStatus Meaning\nNEW File not seen before\nCHANGED Hash differs from last compile\nUNCHANGED Hash matches — skip unless affected\nDELETED Previously tracked file no longer on disk","title":"Step 2: Load State & Detect Changes"},{"category":"section","location":"guide/compilation/#Step-3:-Find-Affected-Sources","page":"Compilation Pipeline","text":"Even unchanged sources may need recompilation if they share concepts with a changed source. The compiler builds a concept-overlap graph and marks these as \"affected\".","title":"Step 3: Find Affected Sources"},{"category":"section","location":"guide/compilation/#Step-4:-Phase-1-—-Extract-Concepts","page":"Compilation Pipeline","text":"For each changed or affected source, the LLM extracts up to max_concepts_per_source key concepts. Each concept becomes an ExtractedConcept with a title and summary.","title":"Step 4: Phase 1 — Extract Concepts"},{"category":"section","location":"guide/compilation/#Step-5:-Find-Late-Affected-Sources","page":"Compilation Pipeline","text":"After extraction, newly discovered concept overlaps may affect additional sources. A second pass catches these \"late-affected\" sources and extracts their concepts too.","title":"Step 5: Find Late-Affected Sources"},{"category":"section","location":"guide/compilation/#Step-6:-Merge-Extractions","page":"Compilation Pipeline","text":"When multiple sources mention the same concept, their extractions are merged into a single MergedConcept that combines content from all contributing sources.","title":"Step 6: Merge Extractions"},{"category":"section","location":"guide/compilation/#Step-7:-Phase-2-—-Generate-Pages","page":"Compilation Pipeline","text":"The LLM generates or updates wiki pages for each merged concept. Each page includes:\n\nYAML frontmatter with metadata (title, summary, sources, tags)\nEncyclopedia-style body content\n[[wikilinks]] to related concepts","title":"Step 7: Phase 2 — Generate Pages"},{"category":"section","location":"guide/compilation/#Step-8:-Handle-Deletions","page":"Compilation Pipeline","text":"Pages whose only source was deleted are marked as orphaned in their frontmatter.","title":"Step 8: Handle Deletions"},{"category":"section","location":"guide/compilation/#Step-9:-Resolve-Wikilinks","page":"Compilation Pipeline","text":"Bidirectional wikilink resolution scans all generated and existing pages, adding [[wikilinks]] around mentions of known concept titles using fuzzy matching.","title":"Step 9: Resolve Wikilinks"},{"category":"section","location":"guide/compilation/#Step-10:-Regenerate-Index","page":"Compilation Pipeline","text":"The wiki/index.md file is regenerated with a table of contents listing all concept and query pages.","title":"Step 10: Regenerate Index"},{"category":"section","location":"guide/compilation/#Step-11:-Log-Operation","page":"Compilation Pipeline","text":"The compilation result is appended to wiki/log.md as an audit trail entry.","title":"Step 11: Log Operation"},{"category":"section","location":"guide/compilation/#Step-12:-Save-State-and-Release-Lock","page":"Compilation Pipeline","text":"Updated source hashes and concept mappings are persisted to state.json, and the filesystem lock is released.","title":"Step 12: Save State & Release Lock"},{"category":"section","location":"guide/compilation/#Two-Phase-Design","page":"Compilation Pipeline","text":"The pipeline uses a two-phase approach to eliminate order-dependence:\n\nPhase 1 (Extract) — Process all sources and extract concepts before generating any pages. This ensures every source's concepts are known upfront.\nPhase 2 (Generate) — Generate pages with full knowledge of all concepts across all sources. Each page can reference concepts from any source.\n\nThis avoids the problem where processing Source A before Source B would miss cross-references that only become apparent after both are processed.","title":"Two-Phase Design"},{"category":"section","location":"guide/compilation/#Incremental-Compilation","page":"Compilation Pipeline","text":"Only sources whose content has changed (different SHA-256 hash) are reprocessed. The detect_changes function classifies each source file:\n\nchanges = detect_changes(config, state)\n# Vector{SourceChange} — each with .file and .status","title":"Incremental Compilation"},{"category":"section","location":"guide/compilation/#Cross-Source-Dependencies","page":"Compilation Pipeline","text":"When Source A and Source B both contribute to the concept \"machine learning\", modifying Source A triggers recompilation of Source B as well. This ensures the shared concept page reflects the latest information from all contributing sources.","title":"Cross-Source Dependencies"},{"category":"section","location":"guide/compilation/#Forced-Recompilation","page":"Compilation Pipeline","text":"Pass force=true to recompile all sources regardless of hash changes:\n\nresult = compile!(config; force=true)\n\nThis is useful after changing the LLM model or compilation prompts.","title":"Forced Recompilation"},{"category":"section","location":"guide/compilation/#Concept-Merging","page":"Compilation Pipeline","text":"When the same concept is extracted from multiple sources, the compiler merges them:\n\nConcept titles are normalized via slugify to detect duplicates\nContent from all contributing sources is concatenated\nThe LLM generates a unified page that synthesizes information from all sources","title":"Concept Merging"},{"category":"section","location":"guide/extensions/#extensions","page":"Extensions","text":"LLMWiki uses Julia's package extension mechanism to provide optional integrations. Extensions are loaded automatically when you import the relevant package alongside LLMWiki.","title":"Extensions"},{"category":"section","location":"guide/extensions/#How-Extensions-Work","page":"Extensions","text":"Julia 1.9+ supports package extensions: code that is loaded only when specific \"weak dependencies\" are available. LLMWiki defines extension stubs in the main module that are overridden when extensions load.\n\nFor example, semantic_search is defined as an empty stub:\n\nfunction semantic_search end  # overridden by LLMWikiMem0Ext\n\nWhen you do using LLMWiki, Mem0, Julia automatically loads ext/LLMWikiMem0Ext.jl, which provides the real implementation.","title":"How Extensions Work"},{"category":"section","location":"guide/extensions/#Mem0.jl-—-Semantic-Search","page":"Extensions","text":"Adds vector-based semantic search using Mem0.jl embeddings.","title":"Mem0.jl — Semantic Search"},{"category":"section","location":"guide/extensions/#Setup","page":"Extensions","text":"using Pkg\nPkg.add(\"Mem0\")\n\nusing LLMWiki, Mem0","title":"Setup"},{"category":"section","location":"guide/extensions/#Usage","page":"Extensions","text":"# Semantic search\nresults = search_wiki(config, \"memory management\"; method=:semantic)\n\n# Hybrid search (BM25 + semantic with RRF fusion)\nresults = search_wiki(config, \"memory management\"; method=:hybrid)\n\nThe extension uses config.embedding_model (default: \"nomic-embed-text\") and respects config.similarity_threshold (default: 0.7) to filter low-confidence matches.\n\nFor Ollama, the embedding endpoint is derived from config.api_url. For OpenAI, set OPENAI_API_KEY in your environment.","title":"Usage"},{"category":"section","location":"guide/extensions/#SQLite-—-State-Persistence","page":"Extensions","text":"Replaces the default JSON-based state storage with a SQLite database, providing durable, queryable state.","title":"SQLite — State Persistence"},{"category":"section","location":"guide/extensions/#Setup-2","page":"Extensions","text":"using Pkg\nPkg.add(\"SQLite\")\n\nusing LLMWiki, SQLite","title":"Setup"},{"category":"section","location":"guide/extensions/#What-Changes","page":"Extensions","text":"When loaded, the extension provides:\n\nload_state_sqlite(config) — Load WikiState from state.db\nsave_state_sqlite(config, state) — Persist state to state.db\n\nThe SQLite database is stored at .llmwiki/state.db and contains tables:\n\nTable Purpose\nsources Per-file hash, concepts list, and compilation timestamp\nwiki_meta Key-value metadata (index hash, version)\nfrozen_slugs Slugs shared between deleted and surviving sources","title":"What Changes"},{"category":"section","location":"guide/extensions/#Benefits","page":"Extensions","text":"Durability — ACID transactions protect against corruption\nQueryability — Run SQL queries directly against wiki state\nConcurrency — SQLite handles concurrent readers safely","title":"Benefits"},{"category":"section","location":"guide/extensions/#RDFLib.jl-—-Knowledge-Graphs","page":"Extensions","text":"Planned integration with RDFLib.jl for exporting the wiki as a knowledge graph.","title":"RDFLib.jl — Knowledge Graphs"},{"category":"section","location":"guide/extensions/#Planned-Features","page":"Extensions","text":"Export wiki concepts as RDF triples (concepts as resources, wikilinks as predicates)\nSPARQL queries over the wiki knowledge graph\nPROV ontology for source provenance tracking\nSHACL validation for wiki page schemas\n\nnote: Note\nThe RDFLib extension is currently a stub. Check the repository for updates.","title":"Planned Features"},{"category":"section","location":"guide/extensions/#WikiAgent-—-AgentFramework.jl-Integration","page":"Extensions","text":"LLMWiki includes a built-in agent that wraps wiki operations as tools for an LLM-powered conversational interface.\n\nusing LLMWiki, AgentFramework\n\nconfig = load_config(\"my-wiki\")\nagent = create_wiki_agent(config)\n\nThe agent provides these tools:\n\nTool Description\nwiki_ingest(path_or_url) Ingest a source file or URL\nwiki_compile() Run the compilation pipeline\nwiki_query(question) Query the wiki knowledge base\nwiki_search(query) Search pages by keyword\nwiki_lint() Run health checks\nwiki_read(slug) Read a specific wiki page\nwiki_status() Show wiki statistics\n\nSee create_wiki_agent for the full API.","title":"WikiAgent — AgentFramework.jl Integration"},{"category":"section","location":"guide/search-query/#search-query","page":"Search & Query","text":"LLMWiki provides both keyword-based search and LLM-powered question answering.","title":"Search & Query"},{"category":"section","location":"guide/search-query/#Search","page":"Search & Query","text":"The search_wiki function supports three search methods:","title":"Search"},{"category":"section","location":"guide/search-query/#BM25-Full-Text-Search","page":"Search & Query","text":"The default search method. Uses the Okapi BM25 ranking algorithm for fast, dependency-free keyword search.\n\nresults = search_wiki(config, \"memory safety\"; method=:bm25)\nfor r in results\n    println(\"$(r.title) ($(r.slug)) — score: $(round(r.score, digits=3))\")\n    println(\"  $(r.snippet)\")\nend\n\nBM25 search works by:\n\nBuilding an in-memory index of all wiki pages (LLMWiki.build_bm25_index)\nTokenizing the query (lowercasing, stopword removal, markdown stripping)\nScoring each document using BM25 term frequency × inverse document frequency\nReturning the top-k results with snippets\n\nYou can also use bm25_search directly on a pre-built index:\n\nindex = LLMWiki.build_bm25_index(config)\nresults = bm25_search(index, \"ownership model\"; top_k=5)","title":"BM25 Full-Text Search"},{"category":"section","location":"guide/search-query/#Semantic-Search","page":"Search & Query","text":"Vector-based semantic search using embeddings. Requires the Mem0.jl extension:\n\nusing LLMWiki, Mem0\nresults = search_wiki(config, \"memory safety\"; method=:semantic)\n\nSemantic search embeds the query and all wiki pages, then ranks by cosine similarity. Results with similarity below config.similarity_threshold are filtered out.","title":"Semantic Search"},{"category":"section","location":"guide/search-query/#Hybrid-Search","page":"Search & Query","text":"Combines BM25 and semantic results using Reciprocal Rank Fusion (RRF):\n\nusing LLMWiki, Mem0\nresults = search_wiki(config, \"memory safety\"; method=:hybrid)\n\nRRF merges ranked lists from both methods using the formula:\n\nscore(d) = Σ 1/(k + rank_i(d))\n\nwhere k=60 is a standard smoothing constant. This ensures that documents ranked highly by either method appear near the top, while documents ranked highly by both methods are boosted further.\n\nIf semantic search is unavailable, hybrid search falls back to BM25-only.","title":"Hybrid Search"},{"category":"section","location":"guide/search-query/#Search-Parameters","page":"Search & Query","text":"top_k — Number of results to return (default: config.search_top_k, which is 10)\nmethod — :bm25, :semantic, or :hybrid\n\nEach result is a SearchResult with fields: slug, title, score, and snippet.","title":"Search Parameters"},{"category":"section","location":"guide/search-query/#Query-Engine","page":"Search & Query","text":"The query_wiki function implements a two-step retrieval-augmented generation (RAG) pipeline:","title":"Query Engine"},{"category":"section","location":"guide/search-query/#Step-1:-Page-Selection","page":"Search & Query","text":"The wiki index is presented to the LLM, which selects the most relevant pages for the question (up to config.query_page_limit pages).","title":"Step 1: Page Selection"},{"category":"section","location":"guide/search-query/#Step-2:-Answer-Synthesis","page":"Search & Query","text":"The selected pages are loaded and sent to the LLM along with the question. The LLM synthesizes a comprehensive answer with [[wikilink]] citations back to the source pages.\n\n# Basic query\nanswer = query_wiki(config, \"How does Rust handle memory safety?\")\nprintln(answer)","title":"Step 2: Answer Synthesis"},{"category":"section","location":"guide/search-query/#Saving-Query-Results","page":"Search & Query","text":"Pass save=true to persist the answer as a query page in wiki/queries/:\n\nanswer = query_wiki(config, \"Compare Rust and C++ memory models\"; save=true)\n\nSaved queries:\n\nAppear in the wiki index\nCan be found by search\nHave their own frontmatter with page_type: query\nTrack which pages were used as sources","title":"Saving Query Results"},{"category":"section","location":"api/types/#Types","page":"Types","text":"","title":"Types"},{"category":"section","location":"api/types/#Configuration","page":"Types","text":"","title":"Configuration"},{"category":"section","location":"api/types/#State","page":"Types","text":"","title":"State"},{"category":"section","location":"api/types/#Content","page":"Types","text":"","title":"Content"},{"category":"section","location":"api/types/#Enums","page":"Types","text":"","title":"Enums"},{"category":"section","location":"api/types/#Search-and-Lint-Results","page":"Types","text":"","title":"Search & Lint Results"},{"category":"type","location":"api/types/#LLMWiki.WikiConfig","page":"Types","text":"WikiConfig\n\nGlobal configuration for a LLMWiki instance.  Controls directory layout, LLM provider settings, compilation limits, and search parameters.\n\n\n\n\n\n","title":"LLMWiki.WikiConfig"},{"category":"type","location":"api/types/#LLMWiki.WikiState","page":"Types","text":"WikiState\n\nPersistent state for the entire wiki.  Serialised to .llmwiki/state.json and used for incremental change detection.\n\n\n\n\n\n","title":"LLMWiki.WikiState"},{"category":"type","location":"api/types/#LLMWiki.SourceEntry","page":"Types","text":"SourceEntry\n\nPer-source state entry that records the content hash and list of concepts extracted from a single source file.\n\n\n\n\n\n","title":"LLMWiki.SourceEntry"},{"category":"type","location":"api/types/#LLMWiki.ExtractedConcept","page":"Types","text":"ExtractedConcept\n\nA single concept extracted from a source file by the LLM.\n\n\n\n\n\n","title":"LLMWiki.ExtractedConcept"},{"category":"type","location":"api/types/#LLMWiki.PageMeta","page":"Types","text":"PageMeta\n\nYAML frontmatter metadata for a wiki page.\n\n\n\n\n\n","title":"LLMWiki.PageMeta"},{"category":"type","location":"api/types/#LLMWiki.ChangeStatus","page":"Types","text":"Status of a source file relative to the last compiled state.\n\n\n\n\n\n","title":"LLMWiki.ChangeStatus"},{"category":"type","location":"api/types/#LLMWiki.LintSeverity","page":"Types","text":"Severity level for lint findings.\n\n\n\n\n\n","title":"LLMWiki.LintSeverity"},{"category":"type","location":"api/types/#LLMWiki.SearchResult","page":"Types","text":"SearchResult\n\nA single search hit returned by search_wiki.\n\n\n\n\n\n","title":"LLMWiki.SearchResult"},{"category":"type","location":"api/types/#LLMWiki.LintIssue","page":"Types","text":"LintIssue\n\nA single lint finding produced by lint_wiki.\n\n\n\n\n\n","title":"LLMWiki.LintIssue"},{"category":"section","location":"api/utilities/#Utilities","page":"Utilities","text":"","title":"Utilities"},{"category":"section","location":"api/utilities/#Frontmatter","page":"Utilities","text":"","title":"Frontmatter"},{"category":"section","location":"api/utilities/#Markdown-Utilities","page":"Utilities","text":"","title":"Markdown Utilities"},{"category":"section","location":"api/utilities/#State-Management","page":"Utilities","text":"","title":"State Management"},{"category":"section","location":"api/utilities/#Configuration","page":"Utilities","text":"","title":"Configuration"},{"category":"section","location":"api/utilities/#Operation-Log","page":"Utilities","text":"","title":"Operation Log"},{"category":"section","location":"api/utilities/#Extension-Stubs","page":"Utilities","text":"","title":"Extension Stubs"},{"category":"function","location":"api/utilities/#LLMWiki.parse_frontmatter","page":"Utilities","text":"parse_frontmatter(content::String) -> (meta::PageMeta, body::String)\n\nParse YAML frontmatter delimited by --- from a markdown file. Returns the parsed PageMeta and the remaining body text. If no frontmatter is found, returns a default PageMeta with title=\"\" and the full content as body.\n\n\n\n\n\n","title":"LLMWiki.parse_frontmatter"},{"category":"function","location":"api/utilities/#LLMWiki.write_frontmatter","page":"Utilities","text":"write_frontmatter(meta::PageMeta) -> String\n\nGenerate YAML frontmatter string with --- delimiters.\n\n\n\n\n\nwrite_frontmatter(meta::PageMeta, body::AbstractString) -> String\n\nSerialize frontmatter + body into a complete Markdown document.\n\n\n\n\n\n","title":"LLMWiki.write_frontmatter"},{"category":"function","location":"api/utilities/#LLMWiki.slugify","page":"Utilities","text":"slugify(title::String) -> String\n\nConvert a concept title to a URL-safe slug.\n\nExamples\n\nslugify(\"Knowledge Compilation\") == \"knowledge-compilation\"\nslugify(\"C++ Templates\") == \"c-templates\"\nslugify(\"  Foo  Bar  \") == \"foo-bar\"\n\n\n\n\n\n","title":"LLMWiki.slugify"},{"category":"function","location":"api/utilities/#LLMWiki.load_state","page":"Utilities","text":"load_state(config::WikiConfig) -> WikiState\n\nRead the wiki state from config.state_file.  Returns an empty WikiState if the file does not exist or cannot be parsed.\n\n\n\n\n\n","title":"LLMWiki.load_state"},{"category":"function","location":"api/utilities/#LLMWiki.save_state","page":"Utilities","text":"save_state(config::WikiConfig, state::WikiState)\n\nPersist state to config.state_file atomically (write to a temporary file then rename).\n\n\n\n\n\n","title":"LLMWiki.save_state"},{"category":"function","location":"api/utilities/#LLMWiki.detect_changes","page":"Utilities","text":"detect_changes(config::WikiConfig, state::WikiState) -> Vector{SourceChange}\n\nWalk config.sources_dir, compare each file's SHA-256 hash against the recorded state, and classify every file as NEW, CHANGED, UNCHANGED, or DELETED.\n\nFiles whose path previously appeared in state.sources but no longer exist on disk are reported as DELETED.\n\n\n\n\n\n","title":"LLMWiki.detect_changes"},{"category":"function","location":"api/utilities/#LLMWiki.load_config","page":"Utilities","text":"load_config(root::String=\".\") -> WikiConfig\n\nLoad wiki configuration from .llmwiki/config.yaml.  If the file does not exist, return default_config(root).\n\n\n\n\n\n","title":"LLMWiki.load_config"},{"category":"function","location":"api/utilities/#LLMWiki.save_config","page":"Utilities","text":"save_config(config::WikiConfig)\n\nPersist the current configuration to .llmwiki/config.yaml. Only non-default values are written so the file stays minimal.\n\n\n\n\n\n","title":"LLMWiki.save_config"},{"category":"function","location":"api/utilities/#LLMWiki.default_config","page":"Utilities","text":"default_config(root::String=\".\") -> WikiConfig\n\nReturn a WikiConfig with all default values rooted at root. Directory paths are made absolute relative to root.\n\n\n\n\n\n","title":"LLMWiki.default_config"},{"category":"function","location":"api/utilities/#LLMWiki.resolve_paths!","page":"Utilities","text":"resolve_paths!(config::WikiConfig) -> WikiConfig\n\nEnsure all directory/file paths in config are absolute, resolving them relative to config.root.  Mutates and returns config.\n\n\n\n\n\n","title":"LLMWiki.resolve_paths!"},{"category":"function","location":"api/utilities/#LLMWiki.log_operation!","page":"Utilities","text":"log_operation!(config::WikiConfig, operation::Symbol, details::String)\n\nAppend an entry to the wiki operation log at config.log_file.\n\nEach entry is formatted as:\n\n## [2026-04-06T19:00:00] operation | details\n\n\n\n\n\n","title":"LLMWiki.log_operation!"},{"category":"function","location":"api/utilities/#LLMWiki.read_log","page":"Utilities","text":"read_log(config::WikiConfig) -> Vector{NamedTuple{(:timestamp,:operation,:details), Tuple{String,String,String}}}\n\nParse the wiki operation log and return a vector of named tuples. Lines that do not match the expected format are silently skipped.\n\n\n\n\n\n","title":"LLMWiki.read_log"},{"category":"function","location":"api/utilities/#LLMWiki.semantic_search","page":"Utilities","text":"semantic_search(config::WikiConfig, query::String; top_k::Int=10) -> Vector{SearchResult}\n\nSemantic vector search over wiki pages. Requires using LLMWiki, Mem0.\n\n\n\n\n\n","title":"LLMWiki.semantic_search"},{"category":"function","location":"api/utilities/#LLMWiki.load_state_sqlite","page":"Utilities","text":"load_state_sqlite(config::WikiConfig) -> WikiState\n\nLoad wiki state from SQLite. Requires using LLMWiki, SQLite.\n\n\n\n\n\n","title":"LLMWiki.load_state_sqlite"},{"category":"function","location":"api/utilities/#LLMWiki.save_state_sqlite","page":"Utilities","text":"save_state_sqlite(config::WikiConfig, state::WikiState)\n\nSave wiki state to SQLite. Requires using LLMWiki, SQLite.\n\n\n\n\n\n","title":"LLMWiki.save_state_sqlite"},{"category":"section","location":"guide/getting-started/#getting-started","page":"Getting Started","text":"This guide walks you through creating your first LLM-maintained wiki.","title":"Getting Started"},{"category":"section","location":"guide/getting-started/#Prerequisites","page":"Getting Started","text":"Julia 1.9+ (1.10+ recommended)\nAn LLM backend — one of:\nOllama (local, free) — easiest to get started\nOpenAI — requires an API key\nAzure AI — enterprise option","title":"Prerequisites"},{"category":"section","location":"guide/getting-started/#Setting-up-Ollama","page":"Getting Started","text":"# Install Ollama (macOS)\nbrew install ollama\n\n# Pull a model\nollama pull qwen3:8b","title":"Setting up Ollama"},{"category":"section","location":"guide/getting-started/#Installation","page":"Getting Started","text":"using Pkg\nPkg.add(url=\"https://github.com/JuliaKnowledge/LLMWiki.jl\")","title":"Installation"},{"category":"section","location":"guide/getting-started/#Creating-Your-First-Wiki","page":"Getting Started","text":"","title":"Creating Your First Wiki"},{"category":"section","location":"guide/getting-started/#1.-Initialize","page":"Getting Started","text":"using LLMWiki\n\n# Create a default config rooted at ./my-wiki\nconfig = default_config(\"my-wiki\")\nconfig.model = \"qwen3:8b\"  # or \"gpt-4o\" for OpenAI\n\n# Create the directory structure\ninit_wiki(config)\n\nThis creates:\n\nmy-wiki/\n├── sources/            # Raw input documents (you add these)\n├── wiki/\n│   ├── concepts/       # LLM-generated concept pages\n│   ├── queries/        # Saved query results\n│   ├── index.md        # Auto-generated table of contents\n│   └── log.md          # Operation log\n└── .llmwiki/\n    ├── config.yaml     # Wiki configuration\n    └── state.json      # Compilation state","title":"1. Initialize"},{"category":"section","location":"guide/getting-started/#2.-Add-Sources","page":"Getting Started","text":"You can ingest local files (Markdown, PDF) and web pages:\n\n# Ingest a local Markdown file\ningest!(config, \"path/to/article.md\")\n\n# Ingest a PDF\ningest!(config, \"path/to/paper.pdf\")\n\n# Ingest a web page (fetched and converted to Markdown)\ningest!(config, \"https://example.com/article\")\n\n# Batch ingest\ningest_batch!(config, [\n    \"file1.md\",\n    \"file2.pdf\",\n    \"https://example.com/page\",\n])\n\nEach call copies the source into sources/ and returns the resulting filename.","title":"2. Add Sources"},{"category":"section","location":"guide/getting-started/#3.-Compile","page":"Getting Started","text":"Run the compilation pipeline to extract concepts and generate wiki pages:\n\nresult = compile!(config)\n# (compiled = 6, skipped = 0, deleted = 0)\n\nThe compiler will:\n\nDetect which sources changed since the last compile\nExtract key concepts from changed sources via LLM\nGenerate or update wiki pages for each concept\nResolve [[wikilinks]] between pages\nRegenerate the index","title":"3. Compile"},{"category":"section","location":"guide/getting-started/#4.-Search","page":"Getting Started","text":"# Full-text BM25 search\nresults = search_wiki(config, \"memory safety\"; method=:bm25)\nfor r in results\n    println(\"$(r.slug) (score: $(round(r.score, digits=3)))\")\nend","title":"4. Search"},{"category":"section","location":"guide/getting-started/#5.-Query","page":"Getting Started","text":"Use the two-step RAG query engine to ask questions:\n\nanswer = query_wiki(config, \"How does Rust handle memory safety?\")\nprintln(answer)\n\n# Save the answer as a query page\nanswer = query_wiki(config, \"Compare Rust and C++ memory models\"; save=true)","title":"5. Query"},{"category":"section","location":"guide/getting-started/#6.-Lint","page":"Getting Started","text":"Check your wiki for structural issues:\n\nissues = lint_wiki(config)\nfor issue in issues\n    println(\"[$(issue.severity)] $(issue.page): $(issue.message)\")\nend","title":"6. Lint"},{"category":"section","location":"guide/getting-started/#7.-Watch-for-Changes","page":"Getting Started","text":"Auto-recompile when sources change:\n\nwatch_wiki(config) do result\n    println(\"Compiled $(result.compiled) pages\")\nend\n# Press Ctrl-C to stop","title":"7. Watch for Changes"},{"category":"section","location":"guide/getting-started/#Full-Worked-Example","page":"Getting Started","text":"using LLMWiki\n\n# Setup\nconfig = default_config(\"rust-wiki\")\nconfig.model = \"qwen3:8b\"\ninit_wiki(config)\n\n# Add some sources about Rust\ningest!(config, \"https://doc.rust-lang.org/book/ch04-01-what-is-ownership.html\")\ningest!(config, \"https://doc.rust-lang.org/book/ch10-02-traits.html\")\n\n# Compile the wiki\nresult = compile!(config)\nprintln(\"Generated $(result.compiled) pages\")\n\n# Check wiki health\nissues = lint_wiki(config)\nprintln(\"Found $(length(issues)) issues\")\n\n# Search\nresults = search_wiki(config, \"ownership\")\nfor r in results\n    println(\"  $(r.title) — $(r.score)\")\nend\n\n# Query\nanswer = query_wiki(config, \"What is Rust's ownership model?\")\nprintln(answer)\n\n# Check status\nstats = wiki_status(config)\nprintln(\"$(stats.page_count) pages from $(stats.source_count) sources\")","title":"Full Worked Example"},{"category":"section","location":"guide/getting-started/#Next-Steps","page":"Getting Started","text":"Configuration — customize LLM settings, paths, and tuning parameters\nCompilation Pipeline — understand the 12-step pipeline\nSearch & Query — BM25, semantic, and hybrid search\nExtensions — add semantic search, SQLite persistence, or knowledge graphs","title":"Next Steps"},{"category":"section","location":"#LLMWiki.jl","page":"Home","text":"An LLM-maintained, incrementally-compiled knowledge base that compounds over time.\n\n(Image: Docs)\n\nLLMWiki.jl is a Julia implementation of Karpathy's LLM Wiki pattern. Feed raw sources — markdown files, PDFs, or web pages — into the wiki and an LLM automatically extracts concepts, generates encyclopedia-style articles, cross-links them with [[wikilinks]], and keeps everything up to date as sources change.\n\nBuilt on AgentFramework.jl for LLM orchestration.","title":"LLMWiki.jl"},{"category":"section","location":"#Key-Features","page":"Home","text":"Incremental compilation — only recompiles sources that changed (SHA-256 change detection)\nCross-source dependencies — when two sources share a concept, changing one triggers recompilation of both\nTwo-phase pipeline — Phase 1 extracts all concepts, Phase 2 generates pages (eliminates order-dependence)\nBidirectional wikilinks — automatic [[wikilink]] insertion with fuzzy title matching\nBM25 search — full-text search over generated wiki pages\nLint engine — detects broken links, orphaned pages, empty content, stale references\nMultiple providers — Ollama, OpenAI, Azure AI via AgentFramework.jl\nInteractive agent — chat with your wiki using create_wiki_agent\nExtensions — optional Mem0.jl (semantic search), SQLite (state backend), RDFLib.jl (knowledge graph)","title":"Key Features"},{"category":"section","location":"#Quick-Start","page":"Home","text":"using LLMWiki\n\n# Initialize a new wiki\nconfig = default_config(\"my-wiki\")\nconfig.model = \"qwen3:8b\"\ninit_wiki(config)\n\n# Add sources and compile\ningest!(config, \"path/to/article.md\")\ncompile!(config)\n\n# Search and query\nresults = search_wiki(config, \"memory safety\"; method=:bm25)\nanswer = query_wiki(config, \"How does Rust handle memory safety?\")\n\nSee the Getting Started guide for a full walkthrough.","title":"Quick Start"},{"category":"section","location":"#Documentation-Overview","page":"Home","text":"Pages = [\n    \"guide/getting-started.md\",\n    \"guide/configuration.md\",\n    \"guide/compilation.md\",\n    \"guide/search-query.md\",\n    \"guide/extensions.md\",\n    \"guide/architecture.md\",\n    \"api/types.md\",\n    \"api/operations.md\",\n    \"api/utilities.md\",\n]\nDepth = 1","title":"Documentation Overview"},{"category":"section","location":"#License","page":"Home","text":"MIT — Copyright 2026 Simon Frost","title":"License"},{"category":"section","location":"api/operations/#Operations","page":"Operations","text":"","title":"Operations"},{"category":"section","location":"api/operations/#Wiki-Lifecycle","page":"Operations","text":"","title":"Wiki Lifecycle"},{"category":"section","location":"api/operations/#Compilation","page":"Operations","text":"","title":"Compilation"},{"category":"section","location":"api/operations/#Ingestion","page":"Operations","text":"","title":"Ingestion"},{"category":"section","location":"api/operations/#Query","page":"Operations","text":"","title":"Query"},{"category":"section","location":"api/operations/#Search","page":"Operations","text":"","title":"Search"},{"category":"section","location":"api/operations/#Lint","page":"Operations","text":"","title":"Lint"},{"category":"section","location":"api/operations/#Watch","page":"Operations","text":"","title":"Watch"},{"category":"section","location":"api/operations/#Agent","page":"Operations","text":"","title":"Agent"},{"category":"function","location":"api/operations/#LLMWiki.init_wiki","page":"Operations","text":"init_wiki(config::WikiConfig)\n\nCreate the full directory structure for a new LLMWiki instance: sources/, wiki/concepts/, wiki/queries/, .llmwiki/. Existing directories are left untouched.\n\n\n\n\n\n","title":"LLMWiki.init_wiki"},{"category":"function","location":"api/operations/#LLMWiki.wiki_status","page":"Operations","text":"wiki_status(config::WikiConfig) -> WikiStats\n\nCompute summary statistics for the wiki by scanning the filesystem.\n\n\n\n\n\n","title":"LLMWiki.wiki_status"},{"category":"function","location":"api/operations/#LLMWiki.compile!","page":"Operations","text":"compile!(config::WikiConfig; force::Bool=false) -> NamedTuple\n\nRun the full compilation pipeline:\n\nLock — Acquire filesystem lock to prevent concurrent compiles.\nDetect — Load state, hash sources, classify changes.\nAffected — Find unchanged sources sharing concepts with changed ones.\nExtract — Call LLM to extract concepts from all changed+affected sources.\nLate-affected — Post-extraction pass for newly discovered overlaps.\nMerge — Merge extraction results by concept slug.\nGenerate — Call LLM to generate/update wiki pages.\nDelete — Mark orphaned pages for deleted sources.\nResolve — Bidirectional wikilink resolution.\nIndex — Regenerate wiki/index.md.\nLog — Append compile operation to the log.\nSave — Persist updated state and release lock.\n\nIf force=true, all sources are recompiled regardless of hash changes.\n\nReturns (compiled=N, skipped=N, deleted=N).\n\n\n\n\n\n","title":"LLMWiki.compile!"},{"category":"function","location":"api/operations/#LLMWiki.ingest!","page":"Operations","text":"ingest!(config::WikiConfig, path_or_url::String; filename::Union{Nothing,String}=nothing) -> String\n\nIngest a source into the wiki. Accepts:\n\nLocal file paths (copies to sources/)\nHTTP/HTTPS URLs (fetches and converts to markdown)\n\nReturns the filename of the ingested source in sources/. If filename is provided, uses that as the target filename; otherwise derives one from the path or URL.\n\n\n\n\n\n","title":"LLMWiki.ingest!"},{"category":"function","location":"api/operations/#LLMWiki.query_wiki","page":"Operations","text":"query_wiki(config::WikiConfig, question::String;\n           save::Bool=false) -> String\n\nAnswer a question using the wiki as a knowledge base via a two-step LLM-driven retrieval-augmented generation (RAG) pipeline:\n\nPage selection — Present the wiki index to the LLM and ask which pages are most relevant to the question.\nAnswer generation — Load the selected pages and ask the LLM to synthesise a comprehensive answer with wiki-link citations.\n\nIf save=true, the answer is persisted as a query page in queries/ and the wiki index is regenerated.\n\nReturns the generated answer text.\n\n\n\n\n\n","title":"LLMWiki.query_wiki"},{"category":"function","location":"api/operations/#LLMWiki.search_wiki","page":"Operations","text":"search_wiki(config::WikiConfig, query::String;\n            method::Symbol=:bm25, top_k::Int=0) -> Vector{SearchResult}\n\nUnified search over wiki pages.\n\nMethods\n\n:bm25 — BM25 keyword search (default, no external dependencies).\n:semantic — Semantic vector search (requires Mem0 extension).\n:hybrid — Combination of BM25 and semantic scores.\n\ntop_k defaults to config.search_top_k when 0.\n\n\n\n\n\n","title":"LLMWiki.search_wiki"},{"category":"function","location":"api/operations/#LLMWiki.bm25_search","page":"Operations","text":"bm25_search(index::BM25Index, query::String; top_k::Int=10) -> Vector{SearchResult}\n\nSearch the BM25 index and return ranked results.\n\nReturns at most top_k results, each with a slug, title (extracted from the indexed content), BM25 score, and a snippet from the first matching sentence.\n\n\n\n\n\n","title":"LLMWiki.bm25_search"},{"category":"function","location":"api/operations/#LLMWiki.lint_wiki","page":"Operations","text":"lint_wiki(config::WikiConfig; verbose::Bool=false) -> Vector{LintIssue}\n\nRun health checks on the wiki and return a list of issues:\n\n:orphan_page — Pages with no inbound wikilinks from other pages.\n:broken_link — Wikilinks pointing to non-existent pages.\n:missing_page — Concepts referenced in links but without their own page.\n:stale_page — Pages whose sources have been modified since last compile.\n:no_source — Pages that have no associated source files in state.\n:empty_page — Pages with very short body content.\n:frontmatter_orphan — Pages explicitly marked orphaned in frontmatter.\n\nIf verbose=true, INFO-level issues are included; otherwise only WARNING and ERROR_SEVERITY issues are returned.\n\n\n\n\n\n","title":"LLMWiki.lint_wiki"},{"category":"function","location":"api/operations/#LLMWiki.watch_wiki","page":"Operations","text":"watch_wiki(config::WikiConfig;\n           callback::Union{Nothing,Function}=nothing,\n           debounce_seconds::Float64=2.0)\n\nWatch the sources directory for changes and auto-recompile the wiki.\n\nUses FileWatching.watch_folder() to receive filesystem events.  Changes are debounced so rapid successive edits trigger only one compilation.\n\nIf callback is provided, it is called after each successful compilation with the result NamedTuple from compile!.\n\nBlocks until interrupted (Ctrl-C / InterruptException).\n\nExample\n\nconfig = load_config(\"./my-wiki\")\nwatch_wiki(config) do result\n    println(\"Compiled $(result.compiled) pages\")\nend\n\n\n\n\n\n","title":"LLMWiki.watch_wiki"},{"category":"function","location":"api/operations/#LLMWiki.create_wiki_agent","page":"Operations","text":"create_wiki_agent(config::WikiConfig) -> AgentFramework.Agent\n\nCreate an AgentFramework Agent with tools for managing a LLMWiki instance.\n\nTools\n\nwiki_ingest(path_or_url) — Ingest a source file or URL\nwiki_compile() — Run the compilation pipeline\nwiki_query(question) — Query the wiki knowledge base\nwiki_search(query) — Search wiki pages by keyword\nwiki_lint() — Run health checks\nwiki_read(slug) — Read a specific wiki page\nwiki_status() — Show wiki statistics\n\nExample\n\nconfig = load_config(\"./my-wiki\")\nagent = create_wiki_agent(config)\nresponse = run_agent(agent, \"What concepts are in the wiki?\")\nprintln(response.text)\n\n\n\n\n\n","title":"LLMWiki.create_wiki_agent"},{"category":"section","location":"guide/architecture/#architecture","page":"Architecture","text":"This page describes the internal architecture of LLMWiki.jl.","title":"Architecture"},{"category":"section","location":"guide/architecture/#Three-Layer-Design","page":"Architecture","text":"LLMWiki is organized into three layers:","title":"Three-Layer Design"},{"category":"section","location":"guide/architecture/#1.-Sources-Layer-(Immutable)","page":"Architecture","text":"Raw input documents in sources/. These are never modified by the compiler. Supported formats:\n\nMarkdown (.md) — copied directly\nPDF (.pdf) — text extracted via PDFIO.jl\nWeb pages (HTTP/HTTPS URLs) — fetched and converted to Markdown via Gumbo.jl + Cascadia.jl","title":"1. Sources Layer (Immutable)"},{"category":"section","location":"guide/architecture/#2.-Wiki-Layer-(LLM-Generated)","page":"Architecture","text":"The output of compilation, stored in wiki/:\n\nconcepts/ — One Markdown file per concept, with YAML frontmatter\nqueries/ — Saved query answers\nindex.md — Auto-generated table of contents\nlog.md — Operation audit trail","title":"2. Wiki Layer (LLM-Generated)"},{"category":"section","location":"guide/architecture/#3.-Schema-Layer-(Metadata)","page":"Architecture","text":"Internal state stored in .llmwiki/:\n\nconfig.yaml — WikiConfig settings\nstate.json — WikiState with source hashes, concept mappings, and frozen slugs\nlock — Filesystem lock for concurrent compilation prevention","title":"3. Schema Layer (Metadata)"},{"category":"section","location":"guide/architecture/#Content-Types","page":"Architecture","text":"Wiki pages have a page_type field in their frontmatter:\n\nType Enum Description\nConcept CONCEPT Main wiki articles about extracted concepts\nEntity ENTITY Pages about specific named entities\nQuery QUERY_PAGE Saved query answers\nOverview OVERVIEW High-level summary pages","title":"Content Types"},{"category":"section","location":"guide/architecture/#State-Management","page":"Architecture","text":"The WikiState struct tracks:\n\nsources — Dict{String, SourceEntry} mapping each source file to its last-known SHA-256 hash and the list of concept slugs extracted from it\nfrozen_slugs — Slugs shared between deleted and surviving sources (preserved during deletion to avoid losing shared content)\nindex_hash — Hash of the last generated index\nversion — State format version for future migrations\n\nState is serialized to JSON via JSON3.jl with StructTypes.Mutable() for round-trip fidelity.","title":"State Management"},{"category":"section","location":"guide/architecture/#Frontmatter-Format","page":"Architecture","text":"Every wiki page has YAML frontmatter between --- delimiters:\n\n---\ntitle: \"Machine Learning\"\nsummary: \"An overview of machine learning concepts and techniques\"\nsources:\n  - \"intro-to-ml.md\"\n  - \"deep-learning-paper.pdf\"\ntags:\n  - \"ai\"\n  - \"data-science\"\norphaned: false\npage_type: concept\ncreated_at: \"2026-04-06T19:00:00\"\nupdated_at: \"2026-04-06T19:30:00\"\n---\n\nThe PageMeta struct represents this metadata. Use parse_frontmatter and write_frontmatter to read/write it.","title":"Frontmatter Format"},{"category":"section","location":"guide/architecture/#Wikilink-Resolution-Algorithm","page":"Architecture","text":"The wikilink resolver adds [[wikilinks]] around mentions of known concept titles:\n\nCollect all known concept titles from existing wiki pages\nSort titles longest-first (to avoid partial matches)\nFor each title, scan page bodies for case-insensitive matches\nSkip matches that are:\nSelf-references (same page)\nAlready inside [[ ]] delimiters\nInside code blocks or inline code\nNot at word boundaries\nWrap valid matches in [[Title]]\n\nFuzzy matching (via Jaro-Winkler similarity from StringDistances.jl) is used to handle minor title variations, with a configurable threshold (default: 0.85).","title":"Wikilink Resolution Algorithm"},{"category":"section","location":"guide/architecture/#Lint-Checks","page":"Architecture","text":"The lint_wiki function performs structural health checks:\n\nCategory Severity Description\n:broken_link WARNING [[wikilink]] points to a non-existent page\n:orphan_page WARNING Page has no inbound links from other pages\n:frontmatter_orphan WARNING Page explicitly marked orphaned: true\n:stale_page WARNING Source modified since last compilation\n:no_source INFO Page has no associated source files\n:empty_page WARNING Page body is very short (< 50 chars)","title":"Lint Checks"},{"category":"section","location":"guide/architecture/#Module-Dependencies","page":"Architecture","text":"LLMWiki.jl\n├── AgentFramework.jl  — LLM chat client and agent framework\n├── JSON3.jl           — State serialization\n├── YAML.jl            — Config and frontmatter parsing\n├── SHA.jl             — Change detection hashing\n├── HTTP.jl            — Web page ingestion\n├── Gumbo.jl           — HTML parsing\n├── Cascadia.jl        — CSS selectors for HTML\n├── PDFIO.jl           — PDF text extraction\n├── StringDistances.jl — Fuzzy title matching\n├── FileWatching.jl    — File change monitoring\n├── Dates.jl           — Timestamps\n└── UUIDs.jl           — Unique identifiers","title":"Module Dependencies"}]
}
